function loadData() {
  try {
    var ver = localStorage.getItem('bt_version');
    if (ver !== String(DATA_VERSION)) {
      var oldBets = null, oldFutures = null, oldSettings = null;
      try { oldBets = JSON.parse(localStorage.getItem('bt_bets')); } catch(e){}
      try { oldFutures = JSON.parse(localStorage.getItem('bt_futures')); } catch(e){}
      try { oldSettings = JSON.parse(localStorage.getItem('bt_settings')); } catch(e){}
      localStorage.removeItem('bt_bets');
      localStorage.removeItem('bt_futures');
      localStorage.removeItem('bt_chat');
      localStorage.removeItem('bt_settings');
      /* Only clear the seed flag if there are no existing bets — prevents seed from
         re-loading on top of a user's real imported bets after a version migration */
      if (!oldBets || !oldBets.length) {
        localStorage.removeItem('bt_seed_v1');
      }
      localStorage.setItem('bt_version', String(DATA_VERSION));
      /* V4 migration: discard bets with bad "Imported Bet" picks, keep good ones */
      function isBadBet(b) { return !b.pick || b.pick === 'Imported Bet' || b.pick === 'Imported'; }
      if (oldBets && Array.isArray(oldBets)) {
        store.bets = oldBets.filter(function(b) { return !isBadBet(b); });
      }
      if (oldFutures && Array.isArray(oldFutures)) {
        store.futures = oldFutures.filter(function(b) { return !isBadBet(b); });
      }
      /* Preserve settings (API keys etc) */
      if (oldSettings) {
        if (oldSettings.defaultStake) store.defaultStake = oldSettings.defaultStake;
        if (oldSettings.oddsApiKey) store.oddsApiKey = oldSettings.oddsApiKey;
        if (oldSettings.claudeApiKey) store.claudeApiKey = oldSettings.claudeApiKey;
      }
      console.log('V4→V5 migration: kept ' + store.bets.length + ' bets, discarded bad imports. Seed data will reload.');
      /* V5 migration: fix bets where the year (2026) was incorrectly parsed as odds (-2026).
         Reconstruct real odds from stake/toWin. P/L values are correct — only odds display is wrong. */
      var fixedOddsCount = 0;
      for (var mi = 0; mi < store.bets.length; mi++) {
        var mb = store.bets[mi];
        if (Math.abs(mb.odds) >= 2020 && Math.abs(mb.odds) <= 2030 && mb.stake > 0 && mb.toWin > 0) {
          /* Reconstruct: if toWin < stake it's a favorite (negative odds), else underdog (positive) */
          if (mb.toWin < mb.stake) {
            mb.odds = -Math.round(mb.stake / mb.toWin * 100);
          } else {
            mb.odds = Math.round(mb.toWin / mb.stake * 100);
          }
          fixedOddsCount++;
        }
      }
      if (fixedOddsCount > 0) console.log('V5 migration: reconstructed odds for ' + fixedOddsCount + ' bets where year was parsed as odds.');
      saveData();
      return;
    }
    /* Granular parsing — a corrupt chat or settings entry cannot wipe bet data */
    var b = localStorage.getItem('bt_bets');
    if (b) { try { store.bets = JSON.parse(b); } catch(e) { console.warn('bt_bets corrupt, resetting bets:', e); store.bets = []; } }
    var f = localStorage.getItem('bt_futures');
    if (f) { try { store.futures = JSON.parse(f); } catch(e) { console.warn('bt_futures corrupt, resetting futures:', e); store.futures = []; } }
    var c = localStorage.getItem('bt_chat');
    if (c) { try { store.chatHistory = JSON.parse(c); } catch(e) { console.warn('bt_chat corrupt, resetting chat:', e); store.chatHistory = []; } }
    var s = localStorage.getItem('bt_settings');
    if (s) {
      try {
        var settings = JSON.parse(s);
        if (settings.defaultStake) store.defaultStake = settings.defaultStake;
        if (settings.oddsApiKey) store.oddsApiKey = settings.oddsApiKey;
        if (settings.claudeApiKey) store.claudeApiKey = settings.claudeApiKey;
      } catch(e) { console.warn('bt_settings corrupt, using defaults:', e); }
    }
    /* Clean up messy matchup/pick fields from external imports */
    function cleanMatchup(str) {
      if (!str) return str;
      var c = str;
      /* Strip all [bracketed] chunks: [CBB], [824], [Mar-22-2026 08:11 PM], [TNT] etc */
      c = c.replace(/\[[^\]]*\]\s*/g, '');
      /* Strip leading dashes */
      c = c.replace(/^[\s-]+/, '');
      /* Strip league text like "ENGLAND - ENGLISH PREMIER LEAGUE -" */
      c = c.replace(/^[A-Z]+\s*-\s*[A-Z][A-Z\s]+LEAGUE\s*-\s*/i, '');
      c = c.replace(/^[A-Z]+\s*-\s*[A-Z][A-Z\s]+CUP\s*-\s*/i, '');
      c = c.replace(/^ENGLAND\s*-\s*/i, '');
      c = c.replace(/^SPAIN\s*-\s*/i, '');
      c = c.replace(/^GERMANY\s*-\s*/i, '');
      c = c.replace(/^ITALY\s*-\s*/i, '');
      c = c.replace(/^FRANCE\s*-\s*/i, '');
      c = c.replace(/^UEFA\s*-\s*[A-Z\s]+-\s*/i, '');
      /* Strip (Score: X-X) including partial/truncated */
      c = c.replace(/\(Score:\s*[\d]+-[\d]+[^)]*\)/gi, '');
      c = c.replace(/\(Score:\s*[\d]+-[\d]+.*$/gi, '');
      /* Strip (#N) seed numbers */
      c = c.replace(/\s*\(#?\d+\)\s*/g, ' ');
      /* Strip bet type suffixes */
      c = c.replace(/\s*\((?:Game|Live Game|Live Regulation Time|First|Second)\)\s*/gi, ' ');
      c = c.replace(/\s*(?:Moneyline|Point Spread|Total|3-Way Moneyline|Spread|Total Points)\s*$/i, '');
      /* Strip odds/spread from matchup (keep just team names) */
      c = c.replace(/\s+[+-]?\d+[½¼¾]?\s*[\(\-]\s*\d+\)?.*$/, '');
      c = c.replace(/\s+[+-]\d{3,}$/, '');
      c = c.replace(/\s+[+-]\d+[½¼¾]?$/, '');
      c = c.replace(/([½¼¾])\s*[+-]?\d{3,5}/, '$1');
      /* Strip trailing whitespace/dashes */
      c = c.replace(/[\s-]+$/, '');
      return c.trim() || str;
    }
    function cleanPick(str) {
      if (!str) return str;
      var c = str;
      /* Strip [date] and [network] prefixes */
      c = c.replace(/\[[^\]]*\]\s*/g, '');
      c = c.replace(/^[\s-]+/, '');
      /* Strip league text */
      c = c.replace(/^[A-Z]+\s*-\s*[A-Z][A-Z\s]+LEAGUE\s*-\s*/i, '');
      c = c.replace(/^ENGLAND\s*-\s*/i, '');
      c = c.replace(/^SPAIN\s*-\s*/i, '');
      c = c.replace(/^GERMANY\s*-\s*/i, '');
      c = c.replace(/^ITALY\s*-\s*/i, '');
      c = c.replace(/^FRANCE\s*-\s*/i, '');
      c = c.replace(/^UEFA\s*-\s*[A-Z\s]+-\s*/i, '');
      /* Strip (Score: X-X...) including partial */
      c = c.replace(/\(Score:\s*[\d]+-[\d]+[^)]*\)/gi, '');
      c = c.replace(/\(Score:\s*[\d]+-[\d]+.*$/gi, '');
      /* Strip bet type suffixes: (Game), (Live Game), Point Spread, Moneyline, Total */
      c = c.replace(/\s*\((?:Game|Live Game|Live Regulation Time|First|Second)\)\s*/gi, ' ');
      c = c.replace(/\s*(?:Moneyline|Point Spread|Total|3-Way Moneyline|Spread|Total Points)\s*$/i, '');
      /* Strip odds from pick: -5½-110, +165, -110, +446 (Score... etc */
      c = c.replace(/\s+[+-]\d{3,5}$/, '');
      c = c.replace(/([½¼¾])\s*[+-]?\d{3,5}/, '$1');
      /* Strip (#N) seed numbers */
      c = c.replace(/\s*\(#?\d+\)\s*/g, ' ');
      c = c.replace(/[\s]+$/, '');
      return c.trim() || str;
    }
    var cleanArrs = [store.bets, store.futures];
    var needSave = false;
    for (var ca = 0; ca < cleanArrs.length; ca++) {
      for (var ci = 0; ci < cleanArrs[ca].length; ci++) {
        var bet = cleanArrs[ca][ci];
        var cm = cleanMatchup(bet.matchup);
        var cp = cleanPick(bet.pick);
        if (cm !== bet.matchup || cp !== bet.pick) { bet.matchup = cm; bet.pick = cp; needSave = true; }
        if (bet.sport === 'MLS') { bet.sport = 'Soccer'; needSave = true; }
        /* Fix bets stuck with "Imported Bet" as pick text */
        var isBadPick = !bet.pick || bet.pick === 'Imported Bet' || bet.pick === 'Imported';
        var isBadMatchup = !bet.matchup || bet.matchup === 'Imported Bet' || bet.matchup === 'Imported';
        if (isBadPick) {
          if (!isBadMatchup) {
            bet.pick = bet.matchup + ' (' + (bet.odds > 0 ? '+' : '') + bet.odds + ')';
          } else {
            /* Both bad — build from sport + odds + stake */
            bet.pick = (bet.sport || 'Bet') + ' ' + (bet.odds > 0 ? '+' : '') + (bet.odds || '?');
            bet.matchup = bet.pick;
          }
          needSave = true;
        }
        if (isBadMatchup && !isBadPick) {
          bet.matchup = bet.pick.replace(/\s*\([+-]?\d+\)\s*$/, '').replace(/\s*[+-]\d{3,}$/, '').trim() || bet.pick;
          needSave = true;
        }
        /* Fix stored matchup that still contains "vs. opponent/TBD" — keep only the real team name */
        if (bet.matchup && /\bvs\b/i.test(bet.matchup) && /\bopponent\b|\btbd\b|\btba\b/i.test(bet.matchup)) {
          var cmOpp = bet.matchup.replace(/\s+vs\.?\s+(?:opponent|tbd|tba)\b.*/i, '').trim();
          if (cmOpp && cmOpp !== bet.matchup) { bet.matchup = cmOpp; needSave = true; }
        }
        /* Fix stored pick text that contains "vs. opponent/TBD" — remove the placeholder */
        if (bet.pick && /vs\.?\s+(?:opponent|tbd|tba)\b/i.test(bet.pick)) {
          var cpOpp = bet.pick.replace(/\s+vs\.?\s+(?:opponent|tbd|tba)\b\s*/i, ' ').trim();
          if (cpOpp && cpOpp !== bet.pick) { bet.pick = cpOpp; needSave = true; }
        }
        /* Clear ESPN enrichment data for settled bets where the matched game is in the future.
           This removes bad enrichment (e.g. Sweet 16 matchup applied to a Round of 32 bet). */
        if (bet.settled && bet.espnMatchup && bet.scheduledStart) {
          var schedMs = new Date(bet.scheduledStart).getTime();
          if (!isNaN(schedMs) && schedMs > Date.now() + 12 * 3600000) {
            delete bet.espnMatchup;
            delete bet.espnGameId;
            delete bet.scheduledStart;
            delete bet.expectedEndTime;
            delete bet.espnScore;
            if (bet.autoSettled) { bet.settled = false; bet.result = null; bet.settledDate = null; delete bet.autoSettled; }
            needSave = true;
          }
        }
      }
    }
    if (needSave) saveData();
    /* Dedup pass: remove cross-source duplicates that slipped through */
    function dedupArray(arr) {
      var seen = {};
      var cleaned = [];
      for (var di = 0; di < arr.length; di++) {
        var b = arr[di];
        var normPick = normalizePickForDedup(b.pick);
        var key = Math.round((b.stake || 0) * 100) + '|' + (b.odds || 0) + '|' + (b.result || 'open') + '|' + normPick;
        if (!seen[key]) {
          seen[key] = true;
          cleaned.push(b);
        }
      }
      return cleaned;
    }
    var preDedupBets = store.bets.length;
    var preDedupFutures = store.futures.length;
    store.bets = dedupArray(store.bets);
    store.futures = dedupArray(store.futures);
    if (store.bets.length < preDedupBets || store.futures.length < preDedupFutures) {
      console.log('Dedup removed ' + (preDedupBets - store.bets.length) + ' duplicate bets, ' + (preDedupFutures - store.futures.length) + ' duplicate futures');
      saveData();
    }
    /* Load seed data if not already loaded */
    if (!localStorage.getItem(SEED_LOADED_KEY)) {
      try {
        var seed = getSeedData();
        if (seed && seed.length > 0) {
          var added = 0;
          for (var si = 0; si < seed.length; si++) {
            if (!isDuplicateBet(seed[si])) { store.bets.push(seed[si]); added++; }
          }
          if (added > 0) { localStorage.setItem(SEED_LOADED_KEY, '1'); saveData(); }
        }
      } catch(e) { console.warn('Seed load failed:', e); }
    }

    /* Load NFL historical data (2023 + 2024 + 2025 seasons) if not already loaded */
    /* MIGRATE v1→v2→v3→v4: v4 replaces 2024 weekly summaries with 239 individual game bets.
       Sourced from TN_FB(2024) tab of the bet-tracking Google Sheet. */
    var hasOldHist = localStorage.getItem('bt_hist_v1') || localStorage.getItem('bt_hist_v2') || localStorage.getItem('bt_hist_v3') || localStorage.getItem('bt_hist_v4');
    if (hasOldHist && !localStorage.getItem('bt_hist_v5')) {
      var oldNFLCount = store.bets.filter(function(b) { return b.sport === 'NFL' && b.source === 'historical'; }).length;
      store.bets = store.bets.filter(function(b) { return !(b.sport === 'NFL' && b.source === 'historical'); });
      localStorage.removeItem('bt_hist_v1');
      localStorage.removeItem('bt_hist_v2');
      localStorage.removeItem('bt_hist_v3');
      localStorage.removeItem('bt_hist_v4');
      console.log('Migrated to v5: cleared ' + oldNFLCount + ' old NFL historical entries; reloading bet-level 2023/2024/2025 data');
    }
    if (!localStorage.getItem(HIST_LOADED_KEY)) {
      try {
        var hist = getHistoricalData();
        if (hist && hist.length > 0) {
          var histAdded = 0;
          for (var hi = 0; hi < hist.length; hi++) {
            if (!isDuplicateBet(hist[hi])) { store.bets.push(hist[hi]); histAdded++; }
          }
          if (histAdded > 0) {
            localStorage.setItem(HIST_LOADED_KEY, '1');
            console.log('Loaded ' + histAdded + ' NFL historical bets (2023 + 2024 + 2025)');
            saveData();
          }
        }
      } catch(e) { console.warn('Historical data load failed:', e); }
    }
    /* PATCH_V1: 4 Bovada bets that the parser missed on first import.
       These are the Texas Tech vs Alabama and Connecticut vs UCLA bets from
       the NCAA Tournament R32 (March 21-22, 2026). */
    if (!localStorage.getItem('bt_patch_v1')) {
      try {
        var patchBets = [
          { id: genId(), sport: 'NCAAMB', matchup: 'Texas Tech vs Alabama', pick: 'Over 164.5 (-110)', odds: -110, stake: 55, toWin: 50.00, settled: true, result: 'L', settledDate: new Date().toISOString(), gameTime: '3/21/2026 7:10 PM', addedDate: new Date().toISOString(), type: 'total' },
          { id: genId(), sport: 'NCAAMB', matchup: 'Texas Tech vs Alabama', pick: 'Texas Tech +12 (-110)', odds: -110, stake: 69, toWin: 62.73, settled: true, result: 'L', settledDate: new Date().toISOString(), gameTime: '3/21/2026 7:10 PM', addedDate: new Date().toISOString(), type: 'spread' },
          { id: genId(), sport: 'NCAAMB', matchup: 'Texas Tech vs Alabama', pick: 'Texas Tech (+500)', odds: 500, stake: 20, toWin: 100.00, settled: true, result: 'L', settledDate: new Date().toISOString(), gameTime: '3/21/2026 7:10 PM', addedDate: new Date().toISOString(), type: 'moneyline' },
          { id: genId(), sport: 'NCAAMB', matchup: 'Connecticut vs UCLA', pick: 'Connecticut -3 (-110)', odds: -110, stake: 69, toWin: 62.73, settled: true, result: 'W', settledDate: new Date().toISOString(), gameTime: '3/22/2026 5:15 PM', addedDate: new Date().toISOString(), type: 'spread' }
        ];
        var pAdded = 0;
        for (var pi = 0; pi < patchBets.length; pi++) {
          if (!isDuplicateBet(patchBets[pi])) { store.bets.push(patchBets[pi]); pAdded++; }
        }
        localStorage.setItem('bt_patch_v1', '1');
        if (pAdded > 0) needSave = true;
        console.log('PATCH_V1: added ' + pAdded + ' missing bets');
      } catch(e) { console.warn('Patch v1 failed:', e); }
    }
    /* Patch v2: fix basketball bets misclassified as NBA when they belong to college teams */
    if (!localStorage.getItem('bt_patch_v2')) {
      try {
        var NBA_TEAM_NAMES = /Cavaliers|Lakers|Spurs|Celtics|Warriors|Nets|Knicks|Bucks|76ers|Sixers|Suns|Heat|Bulls|Mavs|Mavericks|Nuggets|Clippers|Hawks|Grizzlies|Cavs|Wolves|Timberwolves|Pelicans|Raptors|Pacers|Kings|Magic|Wizards|Hornets|Blazers|Trail Blazers|Pistons|Rockets|Thunder|Jazz/i;
        var COLLEGE_SIGNALS = /Cougars|Fighting Illini|Bulldogs|Wildcats|Hoosiers|Longhorns|Razorbacks|Volunteers|Tigers|Bears|Blue Devils|Tar Heels|Mountaineers|Boilermakers|Hawkeyes|Wolverines|Spartans|Buckeyes|Nittany Lions|Ducks|Beavers|Utes|Cougars|Aggies|Aztecs|Flyers|Gaels|Zags|Gonzaga|Creighton|Marquette|Villanova|UConn|Connecticut|Vanderbilt|Nebraska|Purdue|Auburn|Tennessee|Baylor|Kansas|Kentucky|Duke|Iowa|Alabama|Arkansas|Michigan|Florida|Virginia|Louisville|Arizona|Utah State|Missouri|UCLA|San Diego State|Dayton|Saint Mary|Illini/i;
        var p2Fixed = 0;
        for (var pi = 0; pi < store.bets.length; pi++) {
          var b = store.bets[pi];
          if (b.sport === 'NBA') {
            var text = (b.matchup || '') + ' ' + (b.pick || '');
            if (!NBA_TEAM_NAMES.test(text) && COLLEGE_SIGNALS.test(text)) {
              store.bets[pi].sport = 'NCAAMB';
              p2Fixed++;
            }
          }
        }
        localStorage.setItem('bt_patch_v2', '1');
        if (p2Fixed > 0) needSave = true;
        console.log('PATCH_V2: fixed sport on ' + p2Fixed + ' misclassified bets');
      } catch(e) { console.warn('Patch v2 failed:', e); }
    }
  } catch (e) {
    /* Outer catch for truly unexpected errors — do NOT clear localStorage, preserve bet data */
    console.warn('loadData() unexpected error (data preserved):', e);
  }
}

/* Normalize pick text for cross-source duplicate matching */
function normalizePickForDedup(pick) {
  if (!pick) return '';
  var p = pick.toUpperCase().trim();
  /* Strip brackets, dates, network tags */
  p = p.replace(/\[[^\]]*\]\s*/g, '');
  p = p.replace(/^[\s-]+/, '');
  /* Strip league text */
  p = p.replace(/^[A-Z]+\s*-\s*[A-Z][A-Z\s]+LEAGUE\s*-\s*/i, '');
  p = p.replace(/^(?:ENGLAND|SPAIN|GERMANY|ITALY|FRANCE|UEFA)\s*-\s*/i, '');
  p = p.replace(/^UEFA\s*-\s*[A-Z\s]+-\s*/i, '');
  /* Strip bet type suffixes */
  p = p.replace(/\s*\((?:GAME|LIVE GAME|LIVE REGULATION TIME|FIRST|SECOND)\)\s*/gi, ' ');
  p = p.replace(/\s*(?:MONEYLINE|POINT SPREAD|TOTAL|3-WAY MONEYLINE|SPREAD|TOTAL POINTS)\s*$/i, '');
  p = p.replace(/\(SCORE:\s*[\d]+-[\d]+\)/gi, '');
  p = p.replace(/\(#?\d+\)/g, '');
  p = p.trim();
  /* Extract first two significant words (handles "Iowa State" vs "Iowa") */
  var words = p.split(/[\s(]+/);
  var sig = [];
  for (var wi = 0; wi < words.length && sig.length < 2; wi++) {
    var w = words[wi].replace(/[^A-Z]/g, '');
    if (w.length > 0 && !/^(ML|THE|VS|AT|AND|OR)$/.test(w)) sig.push(w);
  }
  return sig.join('_');
}

/* Duplicate detection: match on stake + odds + result + normalized team name */
function isDuplicateBet(newBet) {
  var all = store.bets.concat(store.futures);
  var normNew = normalizePickForDedup(newBet.pick);
  for (var i = 0; i < all.length; i++) {
    var b = all[i];
    if (Math.abs(b.stake - newBet.stake) < 0.01 &&
        b.odds === newBet.odds &&
        b.result === newBet.result &&
        normalizePickForDedup(b.pick) === normNew) {
      return true;
    }
  }
  return false;
}

function saveData() {
  try {
    localStorage.setItem('bt_bets', JSON.stringify(store.bets));
    localStorage.setItem('bt_futures', JSON.stringify(store.futures));
    localStorage.setItem('bt_chat', JSON.stringify(store.chatHistory.slice(-50)));
    localStorage.setItem('bt_settings', JSON.stringify({ defaultStake: store.defaultStake, oddsApiKey: store.oddsApiKey, claudeApiKey: store.claudeApiKey }));
  } catch (e) {
    console.warn('Save failed:', e);
    if (e.name === 'QuotaExceededError' || e.code === 22) {
      var warning = document.createElement('div');
      warning.style.cssText = 'position:fixed;top:12px;right:12px;background:#ff4757;color:#fff;padding:12px 20px;border-radius:8px;z-index:9999;font-family:Inter,sans-serif;font-size:.85rem;box-shadow:0 4px 12px rgba(0,0,0,.4)';
      warning.textContent = 'Storage full — your latest changes may not be saved. Clear old chat history in Settings.';
      document.body.appendChild(warning);
      setTimeout(function() { if (warning.parentNode) warning.parentNode.removeChild(warning); }, 8000);
    }
  }
}


